static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

int db_ftp_config_update(int user_id, const char* host, int port, const char* user, const char* pass, const char* path) {
    if (g_db == NULL) return -1;

    FtpConfig existing;
    if (db_ftp_config_get_by_user(user_id, &existing) == 0) {
        // 已存在，更新
        sqlite3_stmt* stmt;
        int rc = sqlite3_prepare_v2(g_db, UPDATE_FTP_CONFIG, -1, &stmt, NULL);
        if (rc != SQLITE_OK) return -1;

        sqlite3_bind_text(stmt, 1, host ? host : "", -1, NULL);
        sqlite3_bind_int(stmt, 2, port);
        sqlite3_bind_text(stmt, 3, user ? user : "", -1, NULL);
        sqlite3_bind_text(stmt, 4, pass ? pass : "", -1, NULL);
        sqlite3_bind_text(stmt, 5, path ? path : "/", -1, NULL);
        sqlite3_bind_int(stmt, 6, user_id);

        rc = sqlite3_step(stmt);
        sqlite3_finalize(stmt);
        return (rc == SQLITE_DONE) ? 0 : -1;
    }

    // 不存在，插入
    return db_ftp_config_create(user_id, host, port, user, pass, path);
}

